// Get the current item's message content
const message = item.json.message?.content;

// Function to clean text but keep headings/bullets
function cleanText(str) {
  if (typeof str !== 'string') return str;

  // 1. Remove URLs
  str = str.replace(/https?:\/\/\S+/g, '');

  // 2. Remove bold or italic markdown (**text** or *text*)
  str = str.replace(/\*\*(.*?)\*\*/g, '$1'); // bold
  str = str.replace(/\*(.*?)\*/g, '$1');     // italic

  // 3. Remove unnecessary trailing spaces
  str = str.replace(/[ \t]+$/gm, '');

  // 4. Collapse multiple empty lines to a single line
  str = str.replace(/\n{2,}/g, '\n\n');

  // 5. Trim start and end
  str = str.trim();

  return str;
}

// Return cleaned message
return {
  json: {
    ...item.json,
    message: cleanText(message)
  }
};

